import React, { createContext, useState, useCallback, useEffect } from 'react';
import { complaintAPI } from '../services/api/complaintAPI';

/**
 * ComplaintContext
 * Manages all complaint-related state and operations
 */
export const ComplaintContext = createContext();

export const ComplaintProvider = ({ children }) => {
  // State
  const [complaints, setComplaints] = useState([]);
  const [selectedComplaint, setSelectedComplaint] = useState(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);
  const [filters, setFilters] = useState({
    status: '',
    category: '',
    priority: '',
  });

  /**
   * Fetch complaints based on user role
   * Students see only their own, admins see all
   */
  const fetchComplaints = useCallback(async (appliedFilters = null) => {
    setIsLoading(true);
    setError(null);

    try {
      const filtersToUse = appliedFilters || filters;
      const result = await complaintAPI.getComplaints(filtersToUse);

      if (result.success) {
        setComplaints(result.data || []);
      } else {
        setError(result.error || 'Failed to fetch complaints');
      }
    } catch (err) {
      setError(err.message || 'An error occurred');
      console.error('Error fetching complaints:', err);
    } finally {
      setIsLoading(false);
    }
  }, [filters]);

  /**
   * Create a new complaint
   */
  const createComplaint = useCallback(async (complaintData) => {
    setIsLoading(true);
    setError(null);

    try {
      const result = await complaintAPI.createComplaint(complaintData);

      if (result.success) {
        // Add new complaint to list
        setComplaints([result.data, ...complaints]);
        setError(null);
        return { success: true, data: result.data };
      } else {
        setError(result.error);
        return { success: false, error: result.error };
      }
    } catch (err) {
      const errorMsg = err.message || 'Failed to create complaint';
      setError(errorMsg);
      console.error('Error creating complaint:', err);
      return { success: false, error: errorMsg };
    } finally {
      setIsLoading(false);
    }
  }, [complaints]);

  /**
   * Get single complaint with history
   */
  const getComplaintById = useCallback(async (complaintId) => {
    setIsLoading(true);
    setError(null);

    try {
      const result = await complaintAPI.getComplaintById(complaintId);

      if (result.success) {
        setSelectedComplaint(result.data);
        setError(null);
        return { success: true, data: result.data };
      } else {
        setError(result.error);
        return { success: false, error: result.error };
      }
    } catch (err) {
      const errorMsg = err.message || 'Failed to fetch complaint';
      setError(errorMsg);
      console.error('Error fetching complaint:', err);
      return { success: false, error: errorMsg };
    } finally {
      setIsLoading(false);
    }
  }, []);

  /**
   * Update complaint status
   */
  const updateStatus = useCallback(
    async (complaintId, newStatus, reason = '') => {
      setIsLoading(true);
      setError(null);

      try {
        const result = await complaintAPI.updateComplaintStatus(
          complaintId,
          newStatus,
          reason
        );

        if (result.success) {
          // Update complaint in list
          setComplaints(
            complaints.map((c) =>
              c.id === complaintId ? { ...c, status: newStatus } : c
            )
          );

          // Update selected complaint if it's the one we changed
          if (selectedComplaint?.id === complaintId) {
            setSelectedComplaint({ ...selectedComplaint, status: newStatus });
          }

          setError(null);
          return { success: true, data: result.data };
        } else {
          setError(result.error);
          return { success: false, error: result.error };
        }
      } catch (err) {
        const errorMsg = err.message || 'Failed to update status';
        setError(errorMsg);
        console.error('Error updating status:', err);
        return { success: false, error: errorMsg };
      } finally {
        setIsLoading(false);
      }
    },
    [complaints, selectedComplaint]
  );

  /**
   * Assign complaint to staff
   */
  const assignComplaint = useCallback(
    async (complaintId, staffId) => {
      setIsLoading(true);
      setError(null);

      try {
        const result = await complaintAPI.assignComplaint(complaintId, staffId);

        if (result.success) {
          // Update complaint in list
          setComplaints(
            complaints.map((c) =>
              c.id === complaintId
                ? { ...c, assigned_to: staffId, status: 'assigned' }
                : c
            )
          );

          // Update selected complaint if applicable
          if (selectedComplaint?.id === complaintId) {
            setSelectedComplaint({
              ...selectedComplaint,
              assigned_to: staffId,
              status: 'assigned',
            });
          }

          setError(null);
          return { success: true, data: result.data };
        } else {
          setError(result.error);
          return { success: false, error: result.error };
        }
      } catch (err) {
        const errorMsg = err.message || 'Failed to assign complaint';
        setError(errorMsg);
        console.error('Error assigning complaint:', err);
        return { success: false, error: errorMsg };
      } finally {
        setIsLoading(false);
      }
    },
    [complaints, selectedComplaint]
  );

  /**
   * Apply filters and refresh list
   */
  const applyFilters = useCallback(async (newFilters) => {
    setFilters(newFilters);
    await fetchComplaints(newFilters);
  }, [fetchComplaints]);

  /**
   * Clear all filters
   */
  const clearFilters = useCallback(async () => {
    const emptyFilters = { status: '', category: '', priority: '' };
    setFilters(emptyFilters);
    await fetchComplaints(emptyFilters);
  }, [fetchComplaints]);

  /**
   * Clear error message
   */
  const clearError = useCallback(() => {
    setError(null);
  }, []);

  // Load complaints on mount
  useEffect(() => {
    fetchComplaints();
  }, []);

  // Context value
  const value = {
    // State
    complaints,
    selectedComplaint,
    isLoading,
    error,
    filters,

    // Actions
    fetchComplaints,
    createComplaint,
    getComplaintById,
    updateStatus,
    assignComplaint,
    applyFilters,
    clearFilters,
    clearError,
    setSelectedComplaint,
  };

  return (
    <ComplaintContext.Provider value={value}>
      {children}
    </ComplaintContext.Provider>
  );
};

export default ComplaintContext;
